#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        long long *A = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;i++) scanf("%lld",&A[i]);
        int *inc = (int*)malloc(N*sizeof(int));
        int *dec = (int*)malloc(N*sizeof(int));
        inc[0]=1;
        for(int i=1;i<N;i++) inc[i] = (A[i]>A[i-1])? inc[i-1]+1 : 1;
        dec[N-1]=1;
        for(int i=N-2;i>=0;i--) dec[i] = (A[i]>A[i+1])? dec[i+1]+1 : 1;
        int ans=0;
        for(int i=0;i<N;i++){
            int cur = inc[i]+dec[i]-1;
            if(cur>ans) ans=cur;
        }
        printf("%d\n",ans);
        free(A); free(inc); free(dec);
    }
    return 0;
}

