  const inc = new Array(N).fill(1);
  for(let i=1;i<N;i++) inc[i] = (A[i]>A[i-1])? inc[i-1]+1:1;
  const dec = new Array(N).fill(1);
  for(let i=N-2;i>=0;i--) dec[i] = (A[i]>A[i+1])? dec[i+1]+1:1;
  let ans=0;
  for(let i=0;i<N;i++){
    const cur = inc[i]+dec[i]-1;
    if(cur>ans) ans=cur;
  }
  outputs.push(String(ans));
}
